SELECT COALESCE(SUM(amount), 0)
FROM bill
WHERE user_id = #{userId}
AND DATE_FORMAT(date, '%Y-%m') = #{month}

    AND type = #{type}

SELECT c.id as categoryId, c.name as categoryName, c.icon as categoryIcon, c.color as categoryColor, COALESCE(SUM(b.amount), 0) as amount, 0 as percentage FROM category c LEFT JOIN bill b ON c.id = b.category_id AND b.user_id = #{userId} AND DATE_FORMAT(b.date, '%Y-%m') = #{month}
AND b.type = #{type}
WHERE c.type = #{type} GROUP BY c.id, c.name, c.icon, c.color HAVING amount > 0 ORDER BY amount DESC

